window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2016>1","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"Orderliness can be defined as","images":[],"options":{"A":"being punctual to work","B":"studying diligently in school","C":"doing things in a proper way","D":"learning the Western way of life"},"answer":"C","explanation":"Orderliness refers to the quality of doing things in a systematic, organized, and disciplined manner. It does not necessarily relate to punctuality, diligence in studies, or adopting a particular way of life. Therefore, the correct answer is 'doing things in a proper way'.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>2","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Use the sign below to answer this question     The road sign above means","images":["data:image/png;base64,"],"options":{"A":"No entry","B":"Maximum speed limit","C":"No stopping","D":"No parking"},"answer":"A","explanation":"The road sign means No Entry or Road. This is the most appropriate answer","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>3","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"The Traffic in Persons Prohibition and Administration Act was passed in Nigeria in","images":[],"options":{"A":"December 2001","B":"October 2002","C":"August 2003","D":"April 2004"},"answer":"C","explanation":"The Traffic in Persons (Prohibition) Enforcement and Administration Act was passed in Nigeria in August 2003. The Act was established to prohibit trafficking in persons, provide for an effective and comprehensive legal and institutional framework for the prohibition, prevention, detection, prosecution and punishment of human trafficking and related offenses in Nigeria.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>4","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"The process of enabling someone to perform an action which adds values to his/her life is known as","images":[],"options":{"A":"employment","B":"recruitment","C":"socialization","D":"empowerment"},"answer":"D","explanation":"Empowerment is the process of enabling someone to perform an action which adds values to his/her life. It involves giving someone the resources, skills, or authority to do something. This can be in the form of education, training, or mentorship. The other options, employment, recruitment, and socialization, do not fit the definition of the process described in the question.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>5","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"Rates are collected in Nigeria by","images":[],"options":{"A":"Federal Inland Revenue Service","B":"State Ministry of Finance","C":"Local Government Council","D":"Council of Traditional Rulers"},"answer":"C","explanation":"In Nigeria, rates such as property tax, market fees, and other local levies are collected by the Local Government Council. The Federal Inland Revenue Service is responsible for collecting federal taxes like income tax and VAT, while the State Ministry of Finance handles state-level taxes. The Council of Traditional Rulers does not have a role in tax collection.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>6","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The fourth schedule of the 1999 constitution of Nigeria outlines the functions of","images":[],"options":{"A":"federal government","B":"local government","C":"national government","D":"state government"},"answer":"B","explanation":"The fourth schedule of the 1999 constitution of Nigeria outlines the functions of the local government. The local government is the third tier of government in Nigeria and it is the closest to the people. It is responsible for the administration of areas within its jurisdiction, including the implementation of certain federal and state policies, economic planning, and development, as well as the provision of public services.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>7","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"Lack of interest in the country is referred to as political","images":[],"options":{"A":"ignorance","B":"apathy","C":"participation","D":"socialization"},"answer":"B","explanation":"Lack of interest in the country is referred to as political apathy. Political apathy is a feeling of disinterest in the sense of politics or apathy towards politics. It can consist of interest apathy, voter apathy, and civic apathy. It means that an individual has an lack of concern for, or interest in, political matters.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>8","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY","question":"Which of the following instrument is not used by a civil society group?","images":[],"options":{"A":"Propaganda","B":"Boycott","C":"Protest","D":"Violence"},"answer":"D","explanation":"Civil society groups are non-governmental organizations that are involved in the public sphere, expressing the interests and will of citizens. They use various instruments to achieve their goals, such as propaganda, boycotts, and protests. However, violence is not an instrument used by civil society groups. It is against the principles of civil society groups which are based on peaceful advocacy and respect for law and order.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>9","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"The administrative class in the public service is to","images":[],"options":{"A":"implement policies","B":"formulate policies","C":"veto policies","D":"oversee policies"},"answer":"A","explanation":"The administrative class in the public service is responsible for implementing policies. They are the ones who carry out the decisions made by the policy makers. They do not formulate, veto, or oversee policies. These roles are typically performed by the legislative and executive branches of government.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>10","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"\"We the people of the Federal Republic of Nigeria\" is usually the opening phrase of the preamble to","images":[],"options":{"A":"coup announcement","B":"government gazettes","C":"constitution","D":"hansard"},"answer":"C","explanation":"The phrase \"We the people of the Federal Republic of Nigeria\" is the opening phrase of the preamble to the constitution of Nigeria. A preamble is an introductory statement in a document that explains the document's philosophy, purposes, or objectives. In the case of constitutions, it presents the general principles which the constitution seeks to establish.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>11","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS","question":"One of the responsibilities of a good citizen is to","images":[],"options":{"A":"possess an international passport","B":"enjoy all amenities provided by the government","C":"serve the country when required","D":"develop his potentialities to the fullest"},"answer":"C","explanation":"One of the responsibilities of a good citizen is to serve the country when required. This can be in the form of obeying laws, paying taxes, participating in civic duties like voting, and even serving in the military or other public services when called upon. It is part of the social contract that citizens have with their country, where they agree to abide by the rules and work for the betterment of the society in return for protection and rights granted by the state.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>12","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP","question":"Naturalized citizens cannot be denied their legal status as members of a country unless if they","images":[],"options":{"A":"are jailed for one year within seven years of acquiring citizenship","B":"are found guilty to be spies or secret agents for another country","C":"refuse to represent the country in an international sporting event","D":"give adequate information to the host country"},"answer":"B","explanation":"Naturalized citizens can lose their citizenship if they are found guilty of being spies or secret agents for another country. This is because such actions are considered a betrayal of the country's trust and a violation of the loyalty expected from its citizens.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>13","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION","question":"Citizenship education influences an individual to be","images":[],"options":{"A":"patriotic","B":"educated","C":"complacent","D":"competent"},"answer":"A","explanation":"Citizenship education is designed to help individuals understand their rights and responsibilities as citizens, and to encourage them to be active, informed, and responsible members of their community. This includes fostering a sense of patriotism, or love and devotion to one's country.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>14","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Which of the following is not an example of orderliness?","images":[],"options":{"A":"Listening skill","B":"Driving skill","C":"Decorum","D":"Deviance"},"answer":"A","explanation":"Orderliness refers to the quality of being well-organized or following a systematic and established procedure. Listening skill, while important, does not directly relate to the concept of orderliness. Driving skill, decorum, and deviance (which is a lack of orderliness) are more directly related to the concept of orderliness.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>15","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Which of the following statements is not correct?","images":[],"options":{"A":"Valid driver's license must be obtained before attempting to drive","B":"Flowing garment can be worm on a motorcycle or bicycle","C":"Headlight should be used during unfavourable weather","D":"Drivers must not engage in distractive activities while driving"},"answer":"B","explanation":"The statement 'Flowing garment can be worn on a motorcycle or bicycle' is not correct. This is because wearing flowing garments while riding a motorcycle or bicycle can be dangerous as the garment can get caught in the wheels or chain of the vehicle, leading to accidents. The other options are correct as they all relate to safe and responsible driving practices.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>16","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL CONFLICTS","question":"Use the dialogue below to answer this question       Which of the following is a consequence of lack of understanding between the Iwuya and Ipaja?","images":["data:image/png;base64,"],"options":{"A":"Intra-communal conflict","B":"Economic dislocation","C":"Inter-communal feud","D":"Interpersonal violence"},"answer":"A","explanation":"Lack of understanding between the Iwuya and Ipaja is Intra-Communal conflict.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>17","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS","question":"Use the dialogue below to answer this question     The remarks of Ayo in the above dialogue portray the importance of","images":["data:image/png;base64,"],"options":{"A":"struggle against British imperialists","B":"museum for keeping old weapons of war","C":"modern methods of conflict resolution","D":"peace for societal progress and development"},"answer":"D","explanation":"The remarks of Ayo in the above dialogue portray the importance of peace for societal progress and development.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>18","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS","question":"Use the dialogue below to answer this question     From the above dialogue, the Headmaster could be described as a","images":["data:image/png;base64,"],"options":{"A":"conciliator that delights in the peace of the communities","B":"dogged fighter with sound martial skills","C":"good samaritan who values peace","D":"fellow who prefers social unrest to harmonious co-existence"},"answer":"D","explanation":"The headmaster is described as a fellow who prefers social unrest to harmonious co-existence.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>19","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Cultism can best be discouraged through","images":[],"options":{"A":"mentoring of cultists by the rich","B":"provision of jobs for cultists","C":"sensitization on the dangers of cultism","D":"establishment of cultists support groups"},"answer":"C","explanation":"Cultism can best be discouraged through sensitization on the dangers of cultism. Sensitization involves creating awareness and educating people about the negative impacts of cultism. This can be done through various mediums such as seminars, workshops, media campaigns, etc. The aim is to enlighten individuals, especially the youth, about the dangers and consequences of cultism, thereby discouraging their involvement.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>20","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE","question":"Which of the following is a consequence of drug abuse?","images":[],"options":{"A":"Depression","B":"Victimization","C":"Inefficiency","D":"Cowardice"},"answer":"A","explanation":"Depression is a consequence of drug abuse. Drug abuse can lead to a variety of physical and mental health problems. One of these is depression, a mood disorder that causes a persistent feeling of sadness and loss of interest. Drug abuse can lead to depression by altering the levels of neurotransmitters in the brain, which are responsible for mood regulation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>21","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"The effect of human trafficking on the victims is","images":[],"options":{"A":"illiteracy","B":"affluence","C":"exposure","D":"exploitation"},"answer":"D","explanation":"Human trafficking is a form of modern-day slavery where people profit from the control and exploitation of others. The victims of human trafficking are often exploited for purposes such as forced labor, sexual exploitation, and organ trafficking. Therefore, the correct answer is 'exploitation'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>22","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"The general attitude of government and society towards cultism is that of","images":[],"options":{"A":"affection","B":"sympathy","C":"abhorrence","D":"support"},"answer":"C","explanation":"Cultism is a social vice that is generally frowned upon by both the government and society at large due to its negative impacts such as violence, crime, and disruption of academic activities in schools. Therefore, the general attitude of government and society towards cultism is that of 'abhorrence'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>23","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE","question":"Drug abuse can be prevented by","images":[],"options":{"A":"fighting drug addicts","B":"poverty reduction","C":"reducing drugs in circulation","D":"legal sanction"},"answer":"C","explanation":"Drug abuse can be prevented by reducing drugs in circulation. This is because the availability of drugs is a major factor that contributes to drug abuse. If drugs are not readily available, it would be difficult for individuals to abuse them. The other options do not directly address the prevention of drug abuse. Fighting drug addicts does not prevent drug abuse but rather punishes those who are already addicted. Poverty reduction and legal sanctions may indirectly affect drug abuse, but they are not direct methods of prevention.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>24","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING","question":"A major responsible for human trafficking is","images":[],"options":{"A":"hunger","B":"illiteracy","C":"greed","D":"joblessness"},"answer":"C","explanation":"A major responsible for human trafficking is greed. Human trafficking is a crime driven by the potential for profit. Traffickers exploit vulnerable individuals with the promise of financial gain. While factors like hunger, illiteracy, and joblessness can make individuals more vulnerable to trafficking, the root cause is the greed of the traffickers.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>25","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"People living with HIV/AIDS (PLWHA) can be supported by","images":[],"options":{"A":"billing them for antiretroviral therapy","B":"providing drugs for them at subsidized rates","C":"providing special attires for them","D":"providing accommodation for them in designated locations"},"answer":"B","explanation":"People living with HIV/AIDS (PLWHA) can be supported by providing drugs for them at subsidized rates. This is because antiretroviral therapy is a critical part of managing HIV/AIDS, and making these drugs more affordable can significantly improve the quality of life for PLWHA.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>26","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Cult members are particularly hostile to","images":[],"options":{"A":"lecturers","B":"perceived enemies","C":"their group","D":"all students"},"answer":"B","explanation":"Cult members are particularly hostile to perceived enemies. This is because cults often create an 'us versus them' mentality, where anyone outside of the group is seen as a potential threat or enemy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>27","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"Drug law enforcement agencies in Nigeria are not empowered to","images":[],"options":{"A":"execute drug suspects","B":"arrest drug barons","C":"prosecute drug traffickers","D":"rehabilitate drug addicts"},"answer":"A","explanation":"The National Drug Law Enforcement Agency (NDLEA) in Nigeria is empowered to arrest, prosecute drug traffickers and rehabilitate drug addicts. However, they are not empowered to execute drug suspects. Execution is a capital punishment that is only carried out after a court judgement. It is not within the jurisdiction of the NDLEA to execute drug suspects.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>28","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"Which of the following is not a means of reducing the incidence of HIV/AIDS in our society?","images":[],"options":{"A":"Education and enlightenment programme","B":"The use of specially designed cutlery by victims","C":"Avoiding pre-marital and extra-marital sex","D":"Upholding the value of chastity"},"answer":"B","explanation":"The use of specially designed cutlery by victims is not a means of reducing the incidence of HIV/AIDS in our society. HIV/AIDS is not transmitted through sharing of cutlery. It is transmitted through unprotected sex, sharing of sharp objects like needles and from an infected mother to her child during childbirth or breastfeeding. Education and enlightenment programmes, avoiding pre-marital and extra-marital sex, and upholding the value of chastity are all effective means of reducing the incidence of HIV/AIDS.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>29","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS","question":"Youth empowerment promotes","images":[],"options":{"A":"self-reliance","B":"youthful exuberance","C":"pursuit of higher education","D":"foreign scholarship"},"answer":"A","explanation":"Youth empowerment is a process where young people are encouraged to take charge of their lives. They do this by addressing their situation and then take action in order to improve their access to resources and transform their consciousness through their beliefs, values, and attitudes. Youth empowerment aims to improve quality of life. Youth empowerment is often addressed as a gateway to intergenerational equity, civic engagement and democracy building. The most common way in which youth empowerment occurs is through youth-led organizations in which young people's interests are represented and their voices are heard. Therefore, the correct answer is 'self-reliance'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>30","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW","question":"The supreme court of Nigeria helps in law","images":[],"options":{"A":"drafting","B":"application","C":"interpretation","D":"enforcement"},"answer":"C","explanation":"The Supreme Court of Nigeria is the highest court in Nigeria, and its decisions are final. The primary role of the Supreme Court is to interpret the law. This means that the Supreme Court takes the lead in defining the meaning of laws, how they are applied, and whether they violate the constitution. Therefore, the correct answer is 'interpretation'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>31","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY","question":"Democracy thrives most where there is","images":[],"options":{"A":"non partisan judiciary","B":"freedom of speech and association","C":"absence of universal suffrage","D":"one-party system"},"answer":"B","explanation":"Democracy thrives most where there is freedom of speech and association. This is because democracy is a system of government where citizens are allowed to participate in decision making. Freedom of speech and association allows citizens to express their views and form or join groups that share their interests or beliefs. This promotes diversity of opinions and ideas, which is a key feature of a thriving democracy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>32","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW","question":"Rule of law is limited by the following except","images":[],"options":{"A":"state of emergency","B":"habeas corpus","C":"illiteracy","D":"immunity"},"answer":"C","explanation":"The rule of law is not limited by illiteracy. The rule of law is a principle that all people and institutions are subject to and accountable to law that is fairly applied and enforced. Illiteracy, or the inability to read or write, does not limit the application or enforcement of the law. However, state of emergency, habeas corpus, and immunity can limit the rule of law. A state of emergency can suspend certain legal protections, habeas corpus (a legal action through which a person can seek relief from unlawful detention) can be suspended in certain situations, and immunity can protect certain individuals from legal action.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>33","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"Preventive measures of HIV/AIDS do not include","images":[],"options":{"A":"abstinence","B":"screening of blood before transfusion","C":"use of barrier methods","D":"stigmatization of victims"},"answer":"D","explanation":"Stigmatization of victims is not a preventive measure of HIV/AIDS. Stigmatization refers to the act of discriminating or treating someone unfairly due to their condition or status. In the context of HIV/AIDS, stigmatization can actually hinder prevention efforts as it may discourage individuals from getting tested or seeking treatment due to fear of discrimination. The other options listed such as abstinence, screening of blood before transfusion, and use of barrier methods are all recognized preventive measures of HIV/AIDS.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>34","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WHY LEADERS FAIL TO PROTECT THE INTERESTS OF THEIR FOLLOWERS","question":"One of the reasons leaders fail to protect the interest of the followers is","images":[],"options":{"A":"selfishness","B":"inadequate finance","C":"ignorance","D":"rigid policies"},"answer":"A","explanation":"Selfishness is one of the reasons leaders fail to protect the interest of the followers. When leaders are selfish, they prioritize their own interests over the interests of their followers. This can lead to decisions and actions that are detrimental to the followers. The other options listed such as inadequate finance, ignorance, and rigid policies can also contribute to leaders failing to protect the interest of their followers, but they are not the primary reason.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>35","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : TYPES OF POPULAR PARTICIPATION","question":"Which of the following is not a form of political participation?","images":[],"options":{"A":"Taking part in voters' registration exercise","B":"Voting during election","C":"Joining political party","D":"Ballot box stuffing during election"},"answer":"D","explanation":"Political participation refers to the activities by which citizens attempt to influence the selection of political leaders and the policies they pursue. This includes activities like voting, joining political parties, and participating in voters' registration exercises. Ballot box stuffing, however, is an illegal activity that involves tampering with the election process and is not considered a legitimate form of political participation.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>36","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY","question":"Civil society groups perform the following roles during general elections except","images":[],"options":{"A":"educating the voters","B":"serving as watchdog","C":"counting votes","D":"stimulating participation"},"answer":"C","explanation":"Civil society groups play a crucial role in the electoral process. They educate voters about their rights and responsibilities, serve as watchdogs to ensure the election is free and fair, and stimulate participation by encouraging citizens to vote. However, counting votes is not a role of civil society groups. This is typically the responsibility of the electoral commission or other designated election officials.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>37","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"Which of the following is not an example of civil society groups?","images":[],"options":{"A":"United Action for Democracy","B":"United Nations Organization","C":"Transition Monitoring Group","D":"Amnesty International"},"answer":"B","explanation":"A civil society group is a non-governmental organization that operates in the interest of the citizens but outside of the government. The United Nations Organization is not a civil society group. It is an international organization established by sovereign states to promote international cooperation and to create and maintain international order.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>38","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"One of the major complains against public service is","images":[],"options":{"A":"inefficiency","B":"understaffing","C":"victimization","D":"discrimination"},"answer":"A","explanation":"Inefficiency is one of the major complaints against public service. This refers to the inability of the public service to deliver services in a timely, cost-effective, and quality manner. This could be due to various factors such as bureaucracy, lack of resources, corruption, and lack of accountability.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>39","subject":"Civic Education","year":"2016","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : WAYS OF IMPROVING THE PUBLIC SERVICE","question":"Which of the following is not a way of improving public service?","images":[],"options":{"A":"Politicization","B":"Refresher courses","C":"The use of Code of Conduct Bureau","D":"Reformation"},"answer":"A","explanation":"Politicization is not a way of improving public service. It often leads to bias and corruption, which can degrade the quality of public service. On the other hand, refresher courses, the use of Code of Conduct Bureau, and reformation are all strategies that can improve the quality of public service. Refresher courses can update the knowledge and skills of public servants, the Code of Conduct Bureau can enforce ethical standards, and reformation can change outdated systems and processes.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>40","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"Children that are not cared for are mostly prone to","images":[],"options":{"A":"criminal attitudes","B":"terminal diseases","C":"examination failure","D":"forced migration"},"answer":"A","explanation":"Children that are not cared for are mostly prone to criminal attitudes. Lack of care and guidance can lead to behavioral problems and criminal attitudes in children. While it's possible for such children to experience terminal diseases, examination failure, or forced migration, these are not as directly linked to the lack of care as criminal attitudes are.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>41","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM~~EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the monologue below to answer this question   Oh Motherland, you were a precious country, a beacon of hope and aspiration as well as toga of pride of your citizens at independence. However, today you are bedeviled with evil, engulfed in the darkness and to say the obvious, at the edge of total moral collapse. Corruption, fraud, deception and dishonesty are prevalent; drug peddlers are having a field day. In schools and colleges, radicalism, prostitution, cultism, examination malpractice among other social vices are order of the day.    The motherland in the monologue could best be described as","images":[],"options":{"A":"a nation in transition","B":"a morally upgrading country","C":"a socially viable nation","D":"an ethically bankrupt country"},"answer":"D","explanation":"The monologue describes a country that was once a beacon of hope and pride but is now riddled with corruption, fraud, deception, dishonesty, and various social vices. This description aligns with the concept of ethical bankruptcy, which refers to a state where moral principles and values are severely lacking or completely absent. Therefore, the motherland in the monologue can best be described as 'an ethically bankrupt country'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>42","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM~~EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the monologue below to answer this question   Oh Motherland, you were a precious country, a beacon of hope and aspiration as well as toga of pride of your citizens at independence. However, today you are bedeviled with evil, engulfed in the darkness and to say the obvious, at the edge of total moral collapse. Corruption, fraud, deception and dishonesty are prevalent; drug peddlers are having a field day. In schools and colleges, radicalism, prostitution, cultism, examination malpractice among other social vices are order of the day.  In spite of the state of affairs reflected in the above monologue, the citizens can make the country better by being committed to","images":[],"options":{"A":"promoting inter-communal relations","B":"strengthening capacity building","C":"championing moral values","D":"encouraging interpersonal relations"},"answer":"C","explanation":"The monologue describes a country in a state of moral decay. To improve such a situation, the citizens need to uphold and promote moral values. This includes honesty, integrity, and respect for others, among other virtues. By championing moral values, citizens can help to reduce corruption, fraud, and other social vices, thereby making the country better. Therefore, the citizens can make the country better by being committed to 'championing moral values'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>43","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM~~EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the monologue below to answer this question   Oh Motherland, you were a precious country, a beacon of hope and aspiration as well as toga of pride of your citizens at independence. However, today you are bedeviled with evil, engulfed in the darkness and to say the obvious, at the edge of total moral collapse. Corruption, fraud, deception and dishonesty are prevalent; drug peddlers are having a field day. In schools and colleges, radicalism, prostitution, cultism, examination malpractice among other social vices are order of the day.  Based on the monologue above, the best approach to curb decadence in the motherland by","images":[],"options":{"A":"value re-orientation","B":"introducing war against corruption","C":"legalizing capital punishment","D":"sending corrupt officials on exile"},"answer":"A","explanation":"The monologue describes a variety of social issues, including corruption, fraud, drug peddling, radicalism, prostitution, cultism, and examination malpractice. These issues are not just about corruption, but also about moral and ethical decay. Therefore, the best approach to curb this decadence is through 'value re-orientation'. This means changing the mindset and attitudes of the citizens towards positive values and ethics. This is a more comprehensive approach than just introducing war against corruption or legalizing capital punishment, which only address specific issues and not the overall moral decay. Sending corrupt officials on exile does not solve the root cause of the problem, which is the lack of proper values and ethics.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>44","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT","question":"The most important contribution of responsible parenthood to national development is that it","images":[],"options":{"A":"increases youthful population","B":"fosters national integration","C":"augments the nation workforce","D":"breeds dependable citizenry"},"answer":"D","explanation":"Responsible parenthood contributes to national development by breeding dependable citizenry. This is because responsible parents raise children who are likely to become responsible, law-abiding, and productive citizens. These citizens contribute to the development of the nation in various ways, such as by participating in the workforce, paying taxes, and upholding the law. While responsible parenthood may also increase the youthful population, foster national integration, and augment the nation's workforce, these are not the most important contributions. The most important contribution is the creation of a dependable citizenry, as this underpins all other aspects of national development.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>45","subject":"Civic Education","year":"2016","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED","question":"Which of the following can not be easily abused?","images":[],"options":{"A":"cosmetics","B":"stimulant","C":"tobacco","D":"narcotics"},"answer":"A","explanation":"The question asks for the item that cannot be easily abused. Among the options, cosmetics are the least likely to be abused. Stimulants, tobacco, and narcotics are all substances that can be and often are abused, leading to addiction and health problems. Cosmetics, on the other hand, are generally used for enhancing or altering one's appearance and are not typically associated with abuse.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>46","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS","question":"Use the story below to answer this question   Dr. Fajir was the Minister of Works and Urban Development in the Ganiba Republic. As such, he was entrusted with the public fund so that his ministry could construct new roads and rehabilitate the existing ones. Unfortunately, Dr. Fajir embezzled the money entrusted in his care and siphoned same to his foreign accounts. This led to the deplorable conditions of roads in the Republic. The Crime Commission arrested and prosecuted him accordingly. Subsequently, he was given the opportunity to be defended by lawyers of his choice in a Court of Law. However, he was found guilty and sentenced to 15 years imprisonment with hard labour without the option of a fine. In addition, he forfeited all his ill-gotten wealth to the Republic.    Dr. Fajir cannot exercise some basic rights because he","images":[],"options":{"A":"was a suspect in a criminal case","B":"was found guilty of a criminal case","C":"failed to comply with court order","D":"embezzled public fund"},"answer":"B","explanation":"The question is about why Dr. Fajir cannot exercise some basic rights. The story clearly states that he was found guilty of a criminal case, which is why he cannot exercise some basic rights. Being a suspect in a criminal case or failing to comply with a court order does not necessarily result in the loss of basic rights. Embezzling public funds is the crime he committed, but it's the conviction (being found guilty) that results in the loss of rights.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>47","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Use the story below to answer this question   Dr. Fajir was the Minister of Works and Urban Development in the Ganiba Republic. As such, he was entrusted with the public fund so that his ministry could construct new roads and rehabilitate the existing ones. Unfortunately, Dr. Fajir embezzled the money entrusted in his care and siphoned same to his foreign accounts. This led to the deplorable conditions of roads in the Republic. The Crime Commission arrested and prosecuted him accordingly. Subsequently, he was given the opportunity to be defended by lawyers of his choice in a Court of Law. However, he was found guilty and sentenced to 15 years imprisonment with hard labour without the option of a fine. In addition, he forfeited all his ill-gotten wealth to the Republic.  According to the above story, the open trial of Dr. Fajir and his representation by lawyers of his choice in a court of competent jurisdiction is an indication of","images":[],"options":{"A":"respect for habeas corpus","B":"freedom of expression","C":"respect for human rights","D":"freedom of legal representation"},"answer":"C","explanation":"The open trial of Dr. Fajir and his representation by lawyers of his choice in a court of competent jurisdiction is an indication of respect for human rights. This is because the right to a fair trial and the right to legal representation are fundamental human rights. The right to a fair trial ensures that individuals are not unjustly treated or punished without being given an opportunity to defend themselves. The right to legal representation ensures that individuals have the opportunity to be defended by a legal practitioner in court proceedings.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>48","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS","question":"Use the story below to answer this question   Dr. Fajir was the Minister of Works and Urban Development in the Ganiba Republic. As such, he was entrusted with the public fund so that his ministry could construct new roads and rehabilitate the existing ones. Unfortunately, Dr. Fajir embezzled the money entrusted in his care and siphoned same to his foreign accounts. This led to the deplorable conditions of roads in the Republic. The Crime Commission arrested and prosecuted him accordingly. Subsequently, he was given the opportunity to be defended by lawyers of his choice in a Court of Law. However, he was found guilty and sentenced to 15 years imprisonment with hard labour without the option of a fine. In addition, he forfeited all his ill-gotten wealth to the Republic.  Based on the above story, which of the following would Dr. Fajir not be allowed to do while in prison?","images":[],"options":{"A":"Voting during election","B":"Engaging in hard labour","C":"Participating in prison fellowship","D":"Writing examination"},"answer":"A","explanation":"While in prison, Dr. Fajir would not be allowed to vote during elections. This is because in many jurisdictions, including the Ganiba Republic as implied in the story, prisoners are often disenfranchised and do not have the right to vote. This is often justified on the grounds that those who have committed serious crimes against society should not have a say in how society is governed. The other options such as engaging in hard labour, participating in prison fellowship, and writing examination are activities that prisoners are typically allowed to engage in as part of their rehabilitation process.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2016>49","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"The most important place for building good values is the","images":[],"options":{"A":"social welfare centre","B":"workplace","C":"family","D":"media houses"},"answer":"C","explanation":"The family is the first social institution any individual interacts with. It is in the family that a child learns the basic values, norms, and social behavior. The family lays the foundation for the child's personality development. Therefore, the family is the most important place for building good values.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2016>50","subject":"Civic Education","year":"2016","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"Citizen's compliance with tenets of the Nigerian National Pledge will enable the country to","images":[],"options":{"A":"receive reciprocal assistance","B":"witness value clarification","C":"get international aid","D":"experience development"},"answer":"D","explanation":"The Nigerian National Pledge is a pledge to be faithful, loyal and honest, to serve Nigeria with all strength, to defend her unity, uphold her honor and glory, and to obey Nigeria's laws. Compliance with these tenets will lead to a harmonious and peaceful society, which is a prerequisite for development. Therefore, citizen's compliance with the tenets of the Nigerian National Pledge will enable the country to experience development.","marks":"1","difficulty":"1"}];